// Same projection used to build the paths — keep these in sync.
export const PROJECTION = {
  SVG_W: 320,
  SVG_H: 160,
  LNG_MIN: 60,
  LNG_MAX: 150,
  LAT_MIN: -12,
  LAT_MAX: 55,
};

export function project(lng: number, lat: number): {x: number; y: number} {
  const {SVG_W, SVG_H, LNG_MIN, LNG_MAX, LAT_MIN, LAT_MAX} = PROJECTION;
  const x = (lng - LNG_MIN) / (LNG_MAX - LNG_MIN) * SVG_W;
  const y = (1 - (lat - LAT_MIN) / (LAT_MAX - LAT_MIN)) * SVG_H;
  return {x, y};
}
